parameters.jsCode:
// 1. Get the big "Technical Analysis: RSI" object
const allData = items[0].json["Technical Analysis: RSI"];

// 2. Get the list of dates (keys)
const dates = Object.keys(allData);

// 3. Find the newest date (dates are YYYY-MM-DD, so sorting usually works, but usually index 0 is newest)
const newestDate = dates[0];

// 4. Get the specific RSI number for that date
const rsiValue = allData[newestDate]["RSI"];

// 5. Create a clean, single output
return [{
  json: {
    date: newestDate,
    rsi: parseFloat(rsiValue)
  }
}];

